SELECT gene_name, chromosome, start_position
FROM genes
ORDER BY chromosome, start_position;

SELECT sequence_name, sequence_description
FROM vertices
WHERE sequence_type = 'coding';

SELECT gene_id, COUNT(exon_id) AS num_exons
FROM exons
GROUP BY gene_id;

SELECT g.gene_name, e.exon_length
FROM genes g
JOIN exons e ON g.gene_id = e.gene_id
WHERE e.exon_length > (
    SELECT AVG(exon_length) FROM exons
);

SELECT COUNT(*)
FROM access_logs
WHERE user_id = 0 AND data_accessed LIKE '%GeneA exon%';

SELECT intron_id, intron_number, intron_length
FROM introns
WHERE intron_type = 'small nuclear RNA';

SELECT MIN(exon_length), MAX(exon_length), AVG(exon_length)
FROM exons
WHERE gene_id = (SELECT gene_id FROM genes WHERE gene_name = 'GeneA');

SELECT DISTINCT u.username, u.email
FROM users AS u
JOIN user_projects AS up ON u.user_id = up.user_id;
